public class EmergencyAlertSystem {

    private PriorityQueue<EmergencyAlert> alertQueue;

    public EmergencyAlertSystem() {
        alertQueue = new PriorityQueue<>(Comparator.comparingInt((EmergencyAlert alert) -> -alert.severity));
    }

    public void addAlert(int severity, String timestamp) {
        alertQueue.offer(new EmergencyAlert(severity, timestamp));
    }

    public void processEmergencyAlerts() {
        while (!alertQueue.isEmpty()) {
            EmergencyAlert alert = alertQueue.poll();
            displayAlert(alert);
        }
    }

    private void displayAlert(EmergencyAlert alert) {
        System.out.println("Processing Alert: " + alert);
    }

