type StockQuote struct {
	Ticker string
	Price  float64
}

func stockTicker(ticker string, prices []float64, ch chan<- StockQuote) {
	for _, price := range prices {
		ch <- StockQuote{Ticker: ticker, Price: price}
		time.Sleep(500 * time.Millisecond)
	}
}

func streamStockQuotes() {
	quotes := make(chan StockQuote)
	var wg sync.WaitGroup
	tickers := map[string][]float64{
		"GOOGL": {2800.00, 2812.35, 2815.22, 2800.52},
		"AAPL":  {150.45, 151.25, 151.75, 152.00},
		"AMZN":  {3400.12, 3405.75, 3410.25, 3408.75},
	}

	wg.Add(len(tickers))
	for ticker, prices := range tickers {
		go func(ticker string, prices []float64) {
			defer wg.Done()
			stockTicker(ticker, prices, quotes)
		}(ticker, prices)
	}

	go func() {
		var mu sync.Mutex
		tickerData := make(map[string][]float64)

		for quote := range quotes {
			mu.Lock()
			tickerData[quote.Ticker] = append(tickerData[quote.Ticker], quote.Price)
			mu.Unlock()
		}

		for ticker, prices := range tickerData {
			sum := 0.0
			for _, price := range prices {
				sum += price
			}
			average := sum / float64(len(prices))
			fmt.Printf("Average price for %s: %.2f\n", ticker, average)
		}
	}()

	wg.Wait()
	close(quotes)
}

func main() {
	streamStockQuotes()
