    std::set<std::string> uniqueEmails;
    for (const auto& email : emails) {
        auto atPos = email.find('@');
        std::string localPart = email.substr(0, atPos);
        std::string domainPart = email.substr(atPos);

        // Convert to lowercase and normalize dots before '@'
        std::string processedEmail;
        std::transform(localPart.begin(), localPart.end(), localPart.begin(), ::tolower);
        for (char ch : localPart) {
            if (ch != '.') {
                processedEmail += ch;
            }
        }
        processedEmail += domainPart;

        uniqueEmails.insert(processedEmail);
    }
    return uniqueEmails;
