struct LogEntry {
    std::string timestamp;
    std::string content;
};

void sortLogsByTimestamp(std::deque<LogEntry>& logs) {
    std::map<std::string, std::string> mergedLogs;

    // Merge logs with duplicate timestamps
    for (const auto& log : logs) {
        if (mergedLogs.find(log.timestamp) != mergedLogs.end()) {
            mergedLogs[log.timestamp] += " | " + log.content;
        } else {
            mergedLogs[log.timestamp] = log.content;
        }
    }

    // Clear and reorder the deque
    logs.clear();
    for (const auto& [timestamp, content] : mergedLogs) {
        logs.push_back({timestamp, content});
    }

    // Sort logs by timestamp
    std::sort(logs.begin(), logs.end(), [](const LogEntry& a, const LogEntry& b) {
        return a.timestamp < b.timestamp;
    });
}
