public class AnagramDetector {

    public static HashMap<String, Integer> detectAnagramOccurrences(String text, String[] words) {
        HashMap<String, Integer> result = new HashMap<>();
        HashMap<String, String> sortedWordMap = new HashMap<>();

        for (String word : words) {
            String sorted = sortWord(word);
            sortedWordMap.put(sorted, word);
            result.put(word, 0);
        }

        String[] textWords = text.split("\\W+");
        for (String textWord : textWords) {
            String sortedTextWord = sortWord(textWord.toLowerCase());
            if (sortedWordMap.containsKey(sortedTextWord)) {
                String originalWord = sortedWordMap.get(sortedTextWord);
                result.put(originalWord, result.get(originalWord) + 1);
            }
        }

        return result;
    }

    private static String sortWord(String word) {
        char[] chars = word.toLowerCase().toCharArray();
        java.util.Arrays.sort(chars);
        return new String(chars);
    }

}
