std::vector<double> computeRollingAverages(const std::vector<int>& temperatures, int windowSize) {
    std::vector<double> rollingAverages;
    int n = temperatures.size();

    for (int i = 0; i < n; ++i) {
        int start = std::max(0, i - windowSize / 2);
        int end = std::min(n, i + windowSize / 2 + 1);
        double sum = std::accumulate(temperatures.begin() + start, temperatures.begin() + end, 0);
        rollingAverages.push_back(sum / (end - start));
    }

    return rollingAverages;
}
